        if (std::abs(pet.pos.r - wall_pos.r) + std::abs(pet.pos.c - wall_pos.c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (i == builder_id) continue;
        if (humans[i].pos == wall_pos) return false;
    }
