}

void find_best_rectangle() {
    // Find the largest rectangle (by interior area) containing 0 pets
    // Try all possible rectangles with some minimum size
    int best_area = -1;
    int best_r1 = 1, best_c1 = 1, best_r2 = 10, best_c2 = 10;

    // Mark pet positions
    bool has_pet[GRID_SIZE + 2][GRID_SIZE + 2] = {};
    for (const auto& pet : pets) has_pet[pet.pos.r][pet.pos.c] = true;

    // Also mark a 1-cell buffer around each pet (since pets move, give margin)
    bool pet_zone[GRID_SIZE + 2][GRID_SIZE + 2] = {};
    for (const auto& pet : pets) {
        pet_zone[pet.pos.r][pet.pos.c] = true;
        for (int d = 0; d < 4; d++) {
            Point np = {pet.pos.r + DIRS[d].r, pet.pos.c + DIRS[d].c};
