    // Interior is (r1+1,c1+1) to (r2-1,c2-1)
    // We want: no pets in interior, and preferably no pets on perimeter either
    // Perimeter size = total walls to build

    // Use prefix sums for pet counting in interior
    int prefix[GRID_SIZE + 2][GRID_SIZE + 2] = {};
    for (int r = 1; r <= GRID_SIZE; r++)
        for (int c = 1; c <= GRID_SIZE; c++)
            prefix[r][c] = (has_pet[r][c] ? 1 : 0) + prefix[r-1][c] + prefix[r][c-1] - prefix[r-1][c-1];

    auto count_pets_in_rect = [&](int r1, int c1, int r2, int c2) -> int {
        if (r1 > r2 || c1 > c2) return 0;
        return prefix[r2][c2] - prefix[r1-1][c2] - prefix[r2][c1-1] + prefix[r1-1][c1-1];
    };

    // Try rectangles: perimeter is the wall, interior is pet-free
    // Minimum interior size: at least 3x3 = 9 squares
    // Max perimeter we can build: with M humans and 300 turns, we can build a lot
    // But we want the LARGEST interior with 0 pets inside (r1+1..r2-1, c1+1..c2-1)

    for (int r1 = 1; r1 <= GRID_SIZE - 4; r1++) {
        for (int c1 = 1; c1 <= GRID_SIZE - 4; c1++) {
