        int pets_right = count_pets_in_region(good_r1, col + 1, good_r2, GRID_SIZE);
        int fewer_pets = std::min(pets_left, pets_right);
        int fewer_area = (pets_left <= pets_right) ? (col - 1) * (good_r2 - good_r1 + 1) : (GRID_SIZE - col) * (good_r2 - good_r1 + 1);
        int score = fewer_area * 10 - fewer_pets * 200;
        if (score > best_col_score) {
            best_col_score = score;
            best_col = col;
        }
    }

    WallSegment seg2;
    seg2.complete = false;
    for (int r = good_r1; r <= good_r2; r++) seg2.cells.push_back({r, best_col});
    wall_segments.push_back(seg2);

    // Determine the best quadrant
    int pets_left = count_pets_in_region(good_r1, 1, good_r2, best_col - 1);
    int pets_right = count_pets_in_region(good_r1, best_col + 1, good_r2, GRID_SIZE);

    int final_r1, final_r2, final_c1, final_c2;
    if (pets_left <= pets_right) {
        final_r1 = good_r1; final_r2 = good_r2;
        final_c1 = 1; final_c2 = best_col - 1;
    } else {
        final_r1 = good_r1; final_r2 = good_r2;
        final_c1 = best_col + 1; final_c2 = GRID_SIZE;
    }

