    for (int i = 0; i < M; i++) {
        int r = final_r1 + 1 + (i * 2) % (final_r2 - final_r1);
        int c = final_c1 + 1 + (i * 3) % (final_c2 - final_c1);
        r = std::max(final_r1, std::min(final_r2, r));
