    // Building phase: assign humans to unbuilt walls in current segment
    std::vector<int> unbuilt;
    for (int j = 0; j < (int)wall_segments[current_segment].cells.size(); j++) {
        if (!grid[wall_segments[current_segment].cells[j].r][wall_segments[current_segment].cells[j].c]) {
            unbuilt.push_back(j);
        }
    }

    // Greedy assignment: each human gets nearest unbuilt wall
    std::vector<bool> wall_taken(wall_segments[current_segment].cells.size(), false);
    std::vector<int> human_target_wall(M, -1);

    // Sort humans by distance to nearest unbuilt wall (assign closest first)
    std::vector<std::pair<int, std::pair<int, int>>> all_pairs; // (dist, (human, wall))
    for (int hi = 0; hi < M; hi++) {
