        if (human_assigned[hi] || wall_taken[wi]) continue;
        human_assigned[hi] = true;
        wall_taken[wi] = true;
        human_target_wall[hi] = wi;
    }

    for (int i = 0; i < M; i++) {
        if (human_target_wall[i] == -1) {
            // No wall assigned, move toward final target
            actions[i] = bfs_move_toward(humans[i].pos, human_final_targets[i]);
            continue;
        }

        Point wall_pos = wall_segments[current_segment].cells[human_target_wall[i]];

