        int adj_dir = -1;
        for (int d = 0; d < 4; d++) {
            Point check = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
            if (check == wall_pos) { adj_dir = d; break; }
