bool valid(Point p) { return p.r >= 1 && p.r <= GRID_SIZE && p.c >= 1 && p.c <= GRID_SIZE; }
bool passable(Point p) { return valid(p) && !grid[p.r][p.c]; }

char bfs_move_toward(Point from, Point to) {
    if (from == to) return '.';
    if (!valid(from) || !passable(from)) return '.';
    if (!valid(to)) return '.';
    // If target is impassable, try to get adjacent to it
    bool target_passable = passable(to);

    static bool vis[GRID_SIZE + 2][GRID_SIZE + 2];
    static Point parent[GRID_SIZE + 2][GRID_SIZE + 2];
    for (int r = 0; r <= GRID_SIZE + 1; r++)
        for (int c = 0; c <= GRID_SIZE + 1; c++) { vis[r][c] = false; parent[r][c] = {-1,-1}; }
    std::queue<Point> q;
    q.push(from);
    vis[from.r][from.c] = true;
    Point dest = {-1, -1};
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int i = 0; i < 4; i++) {
            Point np = {cur.r + DIRS[i].r, cur.c + DIRS[i].c};
            if (passable(np) && !vis[np.r][np.c]) {
                vis[np.r][np.c] = true;
                parent[np.r][np.c] = cur;
                if (target_passable && np == to) { dest = np; goto done; }
                if (!target_passable) {
                    // Check if np is adjacent to target
                    for (int d = 0; d < 4; d++) {
                        Point adj = {np.r + DIRS[d].r, np.c + DIRS[d].c};
                        if (adj == to) { dest = np; goto done; }
                    }
                }
                q.push(np);
            }
        }
    }
    done:
    if (dest.r == -1) return '.';
    Point step = dest;
    while (!(parent[step.r][step.c] == from)) step = parent[step.r][step.c];
    for (int i = 0; i < 4; i++)
        if (from.r + DIRS[i].r == step.r && from.c + DIRS[i].c == step.c)
            return MOVE_CHARS[i];
    return '.';
}

bool can_build_wall(Point wall_pos) {
    if (!valid(wall_pos)) return false;
