        Point adj = {wall_pos.r + DIRS[d].r, wall_pos.c + DIRS[d].c};
        if (valid(adj) && is_inside(adj)) return adj;
    }
    // Fallback: any adjacent passable cell
    for (int d = 0; d < 4; d++) {
        Point adj = {wall_pos.r + DIRS[d].r, wall_pos.c + DIRS[d].c};
        if (passable(adj)) return adj;
