std::string decide_actions(int turn) {
    std::string actions(M, '.');

    // Check phase transitions
    if (current_phase == GATHER) {
        bool all_inside = true;
        for (int i = 0; i < M; i++) {
            if (!is_inside(humans[i].pos)) { all_inside = false; break; }
        }
        gather_turns++;
        if (all_inside || gather_turns >= MAX_GATHER_TURNS) {
            current_phase = BUILD;
        }
    }

    if (current_phase == BUILD) {
        bool all_built = true;
        for (const auto& w : all_walls) {
            if (!grid[w.r][w.c]) { all_built = false; break; }
        }
        if (all_built) current_phase = SETTLE;
    }

    if (current_phase == GATHER) {
        // Move all humans inside the interior region
        for (int i = 0; i < M; i++) {
            if (is_inside(humans[i].pos)) {
                actions[i] = '.';
            } else {
                // Move toward gather point
                actions[i] = bfs_move_toward(humans[i].pos, gather_point);
            }
        }
        return actions;
    }

    if (current_phase == SETTLE) {
        // Move to center of interior
        Point center = {(interior_r1 + interior_r2) / 2, (interior_c1 + interior_c2) / 2};
        for (int i = 0; i < M; i++) {
            Point target = {center.r + (i % 3) - 1, center.c + (i / 3) - 1};
            target.r = std::max(interior_r1, std::min(interior_r2, target.r));
            target.c = std::max(interior_c1, std::min(interior_c2, target.c));
            if (humans[i].pos == target) actions[i] = '.';
            else actions[i] = bfs_move_toward(humans[i].pos, target);
        }
        return actions;
    }

    // BUILD phase
    // Find unbuilt walls
    std::vector<int> unbuilt;
    for (int j = 0; j < (int)all_walls.size(); j++) {
        if (!grid[all_walls[j].r][all_walls[j].c]) unbuilt.push_back(j);
    }

    if (unbuilt.empty()) {
        current_phase = SETTLE;
        return actions;
    }

    // Assign humans to walls greedily by order in wall list (junction-first)
    // But each human builds from the interior side
    std::vector<int> human_target_wall(M, -1);
    std::vector<bool> human_assigned(M, false);
    std::vector<bool> wall_taken(all_walls.size(), false);

    // Prioritize walls by their index in all_walls (junction first)
    // Assign closest human to each priority wall
    for (int wi : unbuilt) {
        int best_hi = -1;
        int best_dist = 99999;
        for (int hi = 0; hi < M; hi++) {
            if (human_assigned[hi]) continue;
            Point stand = interior_stand_for_wall(all_walls[wi]);
            if (stand.r == -1) continue;
            int dist = std::abs(humans[hi].pos.r - stand.r) + std::abs(humans[hi].pos.c - stand.c);
            if (dist < best_dist) { best_dist = dist; best_hi = hi; }
        }
        if (best_hi >= 0) {
            human_assigned[best_hi] = true;
            wall_taken[wi] = true;
            human_target_wall[best_hi] = wi;
        }
    }

    std::vector<Point> walls_being_built;

    for (int i = 0; i < M; i++) {
        if (human_target_wall[i] == -1) {
            // No wall assigned, stay put or move toward unbuilt walls
            actions[i] = '.';
            continue;
        }

        Point wall_pos = all_walls[human_target_wall[i]];
        if (grid[wall_pos.r][wall_pos.c]) { actions[i] = '.'; continue; }

        // Check if adjacent
        int adj_dir = -1;
        for (int d = 0; d < 4; d++) {
            Point check = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
            if (check == wall_pos) { adj_dir = d; break; }
        }

        if (adj_dir >= 0 && can_build_wall(wall_pos)) {
            actions[i] = BUILD_CHARS[adj_dir];
            walls_being_built.push_back(wall_pos);
        } else if (adj_dir >= 0) {
            // Adjacent but can't build (pet blocking). Try another nearby unbuilt wall we can build
            bool found = false;
            for (int wi : unbuilt) {
                if (wall_taken[wi] && wi != human_target_wall[i]) continue;
                Point wp = all_walls[wi];
                if (grid[wp.r][wp.c]) continue;
                for (int d = 0; d < 4; d++) {
                    Point check = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                    if (check == wp && can_build_wall(wp)) {
                        actions[i] = BUILD_CHARS[d];
                        walls_being_built.push_back(wp);
                        found = true;
                        break;
                    }
                }
                if (found) break;
            }
            if (!found) actions[i] = '.';
        } else {
            // Move toward interior stand position for this wall
            Point stand = interior_stand_for_wall(wall_pos);
            if (stand.r != -1) {
                actions[i] = bfs_move_toward(humans[i].pos, stand);
            } else {
                actions[i] = '.';
            }
        }
    }

    // Validate moves don't go to walls being built
    for (int i = 0; i < M; i++) {
        char a = actions[i];
        if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
            for (int d = 0; d < 4; d++) {
                if (a == MOVE_CHARS[d]) {
                    Point np = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                    for (const auto& wp : walls_being_built) {
                        if (np == wp) { actions[i] = '.'; break; }
                    }
                    // Also don't move into impassable
                    if (!passable(np)) actions[i] = '.';
                    break;
                }
            }
        }
    }

    return actions;
}

